-- =========================
-- DROP + CREATE EMPLOYABILITY KPI TABLE
-- =========================

DROP TABLE IF EXISTS employment_kpis CASCADE;

CREATE TABLE employment_kpis (
  id SERIAL PRIMARY KEY,
  institution_id INTEGER REFERENCES institutions(id),
  graduation_year VARCHAR(10),
  graduates_total INTEGER,
  employed_within_6months INTEGER,
  employed_within_12months INTEGER,
  employability_rate_6m DECIMAL(5,2),
  employability_rate_12m DECIMAL(5,2),
  avg_months_to_employment DECIMAL(5,2),
  national_employment_pct DECIMAL(5,2),
  international_employment_pct DECIMAL(5,2),
  self_employed_pct DECIMAL(5,2),
  recorded_at TIMESTAMP DEFAULT NOW()
);

